// Understanding the three trees:

// What you write (WIDGET TREE):
Scaffold(
  body: Center(child: Text('Hello')),
)
// ↓ Flutter inflates into:
// ELEMENT TREE:
// ScaffoldElement
//   └── CenterElement
//         └── TextElement → holds reference to RenderParagraph

// RENDER OBJECT TREE:
// RenderPositionedBox (Center)
//   └── RenderParagraph (Text) → actual paint logic

// ── Keys: fix identity when position changes ─────────
// Without keys — Flutter uses position to match elements
// PROBLEM: Removing first item shifts everything → wrong state!
Column(children: [
  if (showFirst) const StatefulBox(color: Colors.red),  // position 0
  const StatefulBox(color: Colors.blue),                  // position 1 → 0
])

// ✅ With ValueKey — Flutter matches by key, not position
Column(children: [
  if (showFirst) const StatefulBox(key: ValueKey('red'), color: Colors.red),
  const StatefulBox(key: ValueKey('blue'), color: Colors.blue),
])

// Key types:
// ValueKey — equality by value (item.id)
ListView.builder(
  itemBuilder: (ctx, i) => ItemTile(key: ValueKey(items[i].id), item: items[i]),
)

// ObjectKey — equality by reference
ListTile(key: ObjectKey(userObject))

// UniqueKey — always unique; forces element recreation (resets state)
AnimatedSwitcher(child: Widget(key: UniqueKey())) // new key = new animation

// GlobalKey — access element/state from anywhere
final _scaffoldKey = GlobalKey<ScaffoldState>();
Scaffold(key: _scaffoldKey, ...)
_scaffoldKey.currentState?.openDrawer(); // call imperative API

// GlobalKey<FormState> — form validation
final _formKey = GlobalKey<FormState>();
Form(key: _formKey, child: ...)
if (_formKey.currentState!.validate()) _formKey.currentState!.save();

// ── Layout protocol: constraints down, sizes up ─────
// Custom RenderObject example
class RenderCenteredBox extends RenderBox {
  RenderBox? _child;

  @override
  void performLayout() {
    if (_child == null) {
      size = constraints.smallest;
      return;
    }
    // Pass constraints to child
    _child!.layout(constraints.loosen(), parentUsesSize: true);
    // Set our own size (fill available space)
    size = constraints.biggest;
    // Center the child
    final childParentData = _child!.parentData as BoxParentData;
    childParentData.offset = Offset(
      (size.width - _child!.size.width) / 2,
      (size.height - _child!.size.height) / 2,
    );
  }

  @override
  void paint(PaintingContext context, Offset offset) {
    if (_child == null) return;
    final childParentData = _child!.parentData as BoxParentData;
    context.paintChild(_child!, offset + childParentData.offset);
  }
}

// ── Understanding frame scheduling ─────────────────
// When setState() or notifyListeners() is called:
// 1. SchedulerBinding.scheduleFrame() — requests next vsync
// 2. Next vsync arrives → SchedulerBinding.handleBeginFrame()
// 3. Animations tick
// 4. SchedulerBinding.handleDrawFrame()
// 5. BuildOwner.buildScope() — rebuild dirty elements
// 6. PipelineOwner.flushLayout() — layout dirty render objects
// 7. PipelineOwner.flushCompositingBits()
// 8. PipelineOwner.flushPaint() — paint into layers
// 9. RenderView.compositeFrame() — send to GPU

// ── Debug tools for rendering ──────────────────────
// Show performance overlay
MaterialApp(
  showPerformanceOverlay: true, // UI & GPU frame timing bars
)

// Highlight repaints (flash red when layer repaints)
debugRepaintRainbowEnabled = true;

// Print layout of render tree
debugPrintMarkNeedsLayoutStacks = true;

// Show semantic overlay
SemanticsDebugger(child: MyApp())

// Profile mode is essential — debug mode is 10x slower
// flutter run --profile

// ── Full CustomScrollView example ──────────────────
CustomScrollView(
  physics: const BouncingScrollPhysics(),
  slivers: [
    // Collapsing + parallax app bar
    SliverAppBar(
      expandedHeight: 280,
      pinned: true,     // stays visible when collapsed
      floating: false,
      flexibleSpace: FlexibleSpaceBar(
        title: const Text('Catalog'),
        titlePadding: const EdgeInsets.all(16),
        background: Image.network(heroUrl, fit: BoxFit.cover),
        collapseMode: CollapseMode.parallax,
      ),
    ),

    // Sticky section header
    SliverPersistentHeader(
      pinned: true,
      delegate: _StickyHeader('Featured'),
    ),

    // Lazy grid
    SliverGrid(
      delegate: SliverChildBuilderDelegate(
        (ctx, i) => ProductCard(product: featured[i]),
        childCount: featured.length,
      ),
      gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(
        crossAxisCount: 2, mainAxisSpacing: 8, crossAxisSpacing: 8,
      ),
    ),

    SliverPersistentHeader(pinned: true, delegate: _StickyHeader('All Items')),

    SliverList(
      delegate: SliverChildBuilderDelegate(
        (ctx, i) => ItemTile(item: items[i]),
        childCount: items.length,
      ),
    ),

    // Fill remaining space or show "you're all caught up"
    SliverFillRemaining(
      hasScrollBody: false,
      child: Center(child: Text('All caught up! 🎉')),
    ),
  ],
)

// ── Custom SliverPersistentHeaderDelegate ───────────
class _StickyHeader extends SliverPersistentHeaderDelegate {
  final String title;
  _StickyHeader(this.title);

  @override double get minExtent => 48;
  @override double get maxExtent => 48;

  @override
  Widget build(BuildContext context, double shrinkOffset, bool overlapsContent) {
    return Container(
      color: overlapsContent
          ? Theme.of(context).colorScheme.surface.withOpacity(0.95)
          : Theme.of(context).colorScheme.surface,
      alignment: Alignment.centerLeft,
      padding: const EdgeInsets.symmetric(horizontal: 16),
      child: Text(title,
        style: Theme.of(context).textTheme.titleMedium?.copyWith(
          fontWeight: FontWeight.bold,
        )),
    );
  }

  @override bool shouldRebuild(_StickyHeader old) => title != old.title;
}

// BuildContext is just an Element under the hood
@override
Widget build(BuildContext context) {
  // ✅ Use context only here, in this synchronous frame
  final theme = Theme.of(context);
  final size  = MediaQuery.of(context).size;
  return Container(color: theme.colorScheme.primary, width: size.width);
}

// ── Async + context — capture, then await ───────────
Future<void> _saveAndPop(BuildContext context) async {
  final messenger = ScaffoldMessenger.of(context);   // ✅ capture before await
  final navigator = Navigator.of(context);
  await api.save(form);
  // ❌ Don't use context here — widget may be gone
  messenger.showSnackBar(const SnackBar(content: Text('Saved')));
  navigator.pop();
}

// ── context.mounted (Flutter 3.7+) ──
Future<void> _alt(BuildContext context) async {
  await api.save(form);
  if (!context.mounted) return;     // ✅ short-circuit on unmount
  Navigator.of(context).pop();
}

// ── Walking the tree (rarely needed) ──
class DebugPath extends StatelessWidget {
  const DebugPath({super.key});
  @override
  Widget build(BuildContext context) {
    // Find an ancestor RouteSettings — context.findAncestorWidgetOfExactType
    final settings = ModalRoute.of(context)?.settings;
    debugPrint('rendered under route: ${settings?.name}');
    return const SizedBox.shrink();
  }
}

// ── ❌ Don't store context ────────────────────────
class _LeakyState extends State<MyWidget> {
  late BuildContext _ctx;                  // ❌ may outlive its element
  @override
  Widget build(BuildContext context) {
    _ctx = context;                        // ❌
    return const Placeholder();
  }
  void onLater() {
    // _ctx may be unmounted; using it here can crash or do the wrong thing
  }
}

// You never construct these in app code, but you can observe their state
// for diagnostics.

import 'package:flutter/scheduler.dart';
import 'package:flutter/widgets.dart';
import 'package:flutter/rendering.dart';

void dumpFrameSnapshot() {
  // BuildOwner is on WidgetsBinding
  final buildOwner = WidgetsBinding.instance.buildOwner!;
  // dirty count tells you how big the next build phase will be
  debugPrint('dirty elements: ${(buildOwner as dynamic).debugDirtyElements?.length ?? "-"}');

  // PipelineOwner is on RendererBinding
  final pipeline = RendererBinding.instance.pipelineOwner;
  debugPrint('needs paint: ${pipeline.debugNodesNeedingPaint?.length ?? "-"}');

  // Flushing manually is supported for tests; almost never in app code
  // SchedulerBinding.instance.scheduleFrame(); // request another frame
}

// ── How setState reaches BuildOwner ─────────────────
// State.setState(fn)
//   → fn();                          // mutate state
//   → _element.markNeedsBuild();     // mark this element dirty
//   → BuildOwner.scheduleBuildFor()  // queues the element
//   → SchedulerBinding.scheduleFrame() // ask for vsync
// next frame:
//   → BuildOwner.buildScope()        // walks dirty list, calls build()

// ── How a RenderObject change reaches PipelineOwner ─
// renderObject.markNeedsLayout()
//   → PipelineOwner.requestVisualUpdate()
//   → SchedulerBinding.scheduleFrame()
// next frame:
//   → PipelineOwner.flushLayout()    // recompute sizes
//   → PipelineOwner.flushPaint()     // repaint dirty nodes

// ── RepaintBoundary — explicit layer separation ─────
Stack(
  children: [
    // Static, expensive background — repainting once is fine
    RepaintBoundary(child: const BlueprintGrid()),

    // Animated dot moves over the background; without RepaintBoundary, the
    // background would repaint with each dot frame
    Positioned(
      left: _dx,
      top: _dy,
      child: const _Dot(),
    ),
  ],
);

// ── Opacity — creates layer; prefer alpha colors when content is static ──
// Heavy:
Opacity(opacity: 0.6, child: const Banner());
// Cheap:
DecoratedBox(
  decoration: BoxDecoration(color: Colors.black.withValues(alpha: 0.6)),
  child: const Banner(),
);

// ── BackdropFilter — always a new ImageFilterLayer ──
// Limit the area and cache when underlying content is static
ClipRect(
  child: SizedBox(
    width: 240, height: 56,
    child: RepaintBoundary(
      child: BackdropFilter(
        filter: ImageFilter.blur(sigmaX: 12, sigmaY: 12),
        child: const ColoredBox(color: Color(0x22FFFFFF)),
      ),
    ),
  ),
);

// ── Profile what's happening ─────────────────────
// In main():
// debugPaintLayerBordersEnabled = true;   // outlines for layer boundaries
// debugRepaintRainbowEnabled    = true;   // flashes when a layer repaints
//
// In DevTools → Inspector → "Highlight Repaints" toggles the same flag.

// ── HitTestBehavior — controls hit-test on transparent areas ──
// 1) Transparent SizedBox — no hits unless behavior set
GestureDetector(
  onTap: () => debugPrint('tap'),
  child: const SizedBox.expand(),         // ❌ transparent — no hits
);

// 2) Translucent — empty areas still receive hits
GestureDetector(
  behavior: HitTestBehavior.translucent,  // ✅ tap-on-blank works
  onTap: () => debugPrint('tap'),
  child: const SizedBox.expand(),
);

// 3) Opaque — blocks descendants from being hit
GestureDetector(
  behavior: HitTestBehavior.opaque,
  onTap: () {},
  child: Stack(children: const [InvisibleChild(), VisibleChild()]),
);

// ── IgnorePointer / AbsorbPointer ──
IgnorePointer(
  ignoring: _disabled,
  child: TextField(...),                   // disabled = no taps reach it
);

AbsorbPointer(
  absorbing: _intercept,
  child: const ListView(/* ... */),        // taps consumed here, not by children
);

// ── Custom hit testing in a RenderObject ──
class RenderBubble extends RenderBox {
  // Treat hits inside a circle as in-bounds, outside as missed
  @override
  bool hitTestSelf(Offset position) {
    final c = size.center(Offset.zero);
    return (position - c).distance <= size.shortestSide / 2;
  }

  @override
  bool hitTestChildren(BoxHitTestResult result, {required Offset position}) {
    return false;  // no children to test
  }
}

