// ── Default — adequate for most cases ──
ElevatedButton(
  onPressed: _save,
  child: const Text('Save'),                 // label = 'Save', role = button
);

// ── Custom widget with explicit semantics ──
Widget statusDot(bool ok) => Semantics(
  label: ok ? 'Connection healthy' : 'Connection lost',
  liveRegion: !ok,                           // screen reader announces on change
  child: Container(
    width: 12, height: 12,
    decoration: BoxDecoration(
      color: ok ? Colors.green : Colors.red,
      shape: BoxShape.circle,
    ),
  ),
);

// ── Decorative image — exclude from a11y ──
Image.asset(
  'assets/divider.png',
  semanticLabel: '',                         // explicitly empty
  excludeFromSemantics: true,
);

// ── Tap-able non-button — wrap so it's announced as a button ──
GestureDetector(
  onTap: _open,
  child: Semantics(
    button: true,
    label: 'Open settings',
    child: const Icon(Icons.settings),
  ),
);

// ── Merge a label + value into one node ──
MergeSemantics(
  child: Row(children: [
    const Text('Battery'),
    const SizedBox(width: 8),
    Text('$pct%'),                            // "Battery 87%"
  ]),
);

// ── Suppress noise — counters that change rapidly ──
ExcludeSemantics(
  child: Text('$frame fps'),                  // not announced
);

// ── Inspect what the OS sees ──
MaterialApp(
  builder: (_, child) => SemanticsDebugger(child: child!),
);

